const bot = $input.first().json.bot_message || '';
const user = $input.first().json.user_message || '';

// Extrair preços (R$ XX,XX)
const precos = [];
let m;
const re = /R\$\s?([\d.,]+)/g;
while ((m = re.exec(bot)) !== null) precos.push(m[1]);

// Total
const totalMatch = bot.match(/[Tt]otal[:\s]*R\$\s?([\d.,]+)/);
const valorTotal = totalMatch ? totalMatch[1] : null;

// Hints rápidos
const hints = [];
if (bot.match(/kit|rolo.*bandeja|bandeja.*fita/i)) hints.push('upsell');
if (bot.match(/deixo separado|anotado.*atendimento|pode vir/i)) hints.push('fechamento');
if (bot.match(/vou chamar|vendedor|atendente/i)) hints.push('vendedor');
if (bot.match(/não encontr|nao encontr|não temos|nao temos/i)) hints.push('nao_encontrou');
if (bot.match(/R\$/)) hints.push('tem_preco');
if (bot.match(/Oi!.*Sou o TARS|Me conta.*precisa/i)) hints.push('saudacao');
if (bot.match(/Qual (cor|tamanho|volume|acabamento)/i)) hints.push('pergunta');
if (user.match(/mais barato|mais em conta/i)) hints.push('pediu_barato');
if (user.match(/fecha|quero esse|pode separar|vou levar|esse mesmo/i)) hints.push('aceitou');

const prompt = `Classifique esta interacao de atendimento de loja de tintas. Responda APENAS JSON valido.

Cliente: "${user.substring(0, 300)}"
Bot: "${bot.substring(0, 500)}"
Hints: ${JSON.stringify(hints)}
Precos: ${JSON.stringify(precos)}

JSON esperado:
{"evento":"TIPO","produtos":[{"nome":"","marca":"","preco":"","volume":""}],"valor_total":null,"sentimento":"neutro","detalhes":"resumo 1 frase"}

TIPOS (escolha UM):
saudacao | busca_produto | produto_nao_encontrado | pergunta_dados | orcamento_gerado | orcamento_aceito | pediu_mais_barato | upsell_oferecido | upsell_aceito | upsell_recusado | pediu_vendedor | fora_escopo | informacao | encerramento | conversa_geral

Regras:
- busca_produto = bot mostrou produto COM preco
- orcamento_gerado = bot mostrou orcamento formatado com total
- orcamento_aceito = cliente confirmou que quer (fecha, quero, pode separar)
- Use hints como apoio mas classifique pelo conteudo real
- Extraia produtos APENAS se bot mencionou nome E preco`;

return [{
  json: {
    ...($input.first().json),
    _prompt: prompt,
    _precos: precos,
    _valorTotal: valorTotal,
    _hints: hints
  }
}];

const input = $input.first().json;
const original = $('Extrair e Preparar').first().json;

let classificacao = { evento: 'erro_classificacao', detalhes: 'Sem resposta' };

try {
  const content = input.choices?.[0]?.message?.content || '{}';
  classificacao = JSON.parse(content);
} catch(e) {
  classificacao = { evento: 'erro_classificacao', detalhes: 'JSON invalido: ' + e.message };
}

// Sanitizar strings pra SQL
const safe = (s) => s ? s.replace(/'/g, "''") : null;

return [{
  json: {
    conversation_id: original.conversation_id,
    empresa_id: original.empresa_id,
    loja_id: original.loja_id || null,
    phone: original.phone,
    nome_cliente: safe(original.nome),
    evento: classificacao.evento || 'desconhecido',
    produtos_mencionados: JSON.stringify(classificacao.produtos || []),
    valor_total: classificacao.valor_total || null,
    sentimento: classificacao.sentimento || 'neutro',
    user_message: safe((original.user_message || '').substring(0, 500)),
    bot_message: safe((original.bot_message || '').substring(0, 500)),
    detalhes: safe(classificacao.detalhes || '')
  }
}];

